+
+        let clear_cell = Cell::transparent();
+        for cell in &mut self.cells {
+            if let CellContent::Grapheme(id) = cell.content {
+                if id.pool_id() != 0 {
+                    pool.decref(id);
+                }
+            }
+            *cell = clear_cell;
+        }
+    }
